// src/components/DashboardAluno.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

export default function DashboardAluno() {
  const { user } = useAuth();
  const [agendamentos, setAgendamentos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // busca todos os agendamentos do aluno logado
    axios
      .get("/api/agendamentos/meus")
      .then((res) => {
        setAgendamentos(res.data);
      })
      .catch((err) => {
        console.error("Erro ao carregar agendamentos:", err.response?.data || err);
      })
      .finally(() => setLoading(false));
  }, []);

  // Conta quantos estão em cada categoria
  const totalSolicitacoes = agendamentos.filter(a => a.status === "Solicitado").length;
  const totalProximos = agendamentos.filter(a => a.status !== "Solicitado" && a.status !== "Atendido").length;
  const totalAtendidos = agendamentos.filter(a => a.status === "Atendido").length;

  const firstName = (user.usuario || "").split(" ")[0];

  if (loading) {
    return <p className="text-center py-8">Carregando seu dashboard...</p>;
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <h1 className="text-3xl font-bold mb-8">Olá, {firstName}!</h1>

      <div className="bg-blue-100 rounded-2xl shadow p-8 mb-8">
        <div className="text-lg font-semibold mb-4">Resumo rápido</div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white rounded-xl p-6 shadow text-center">
            <div className="font-bold text-3xl text-[#3172C0]">{totalSolicitacoes}</div>
            <div className="text-gray-600 mt-2">Minhas Solicitações</div>
          </div>
          <div className="bg-white rounded-xl p-6 shadow text-center">
            <div className="font-bold text-3xl text-[#3172C0]">{totalProximos}</div>
            <div className="text-gray-600 mt-2">Agendamentos Próximos</div>
          </div>
          <div className="bg-white rounded-xl p-6 shadow text-center">
            <div className="font-bold text-3xl text-[#3172C0]">{totalAtendidos}</div>
            <div className="text-gray-600 mt-2">Agendamentos Atendidos</div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow p-6">
        <h2 className="text-lg font-bold mb-4">Últimas Solicitações</h2>
        <ul className="space-y-3">
          {agendamentos
            .filter(a => a.status === "Solicitado")
            .slice(0, 5)
            .map((a) => (
              <li
                key={a.id}
                className="flex justify-between items-center bg-gray-50 rounded-xl px-5 py-3 shadow-sm"
              >
                <span className="text-gray-800 font-medium">
                  {a.data.slice(0,10).split('-').reverse().join('/')}
                </span>
                <span className="px-4 py-1 rounded-full bg-yellow-100 text-yellow-800 font-semibold">
                  Pendente
                </span>
              </li>
            ))}
          {totalSolicitacoes === 0 && (
            <li className="text-gray-500">Nenhuma solicitação pendente.</li>
          )}
        </ul>
      </div>
    </div>
);
}
